import java.util.*;class A{public static void main(String[]a){var s=new Scanner(System.in);int L=s.nextInt(),C=s.nextInt(),N=s.nextInt();int[]g=new int[N];for(int i=0;i<N;i++)g[i]=s.nextInt();long t=0;int r=0,h=0;var m=new HashMap<Integer,long[]>();while(r<C){if(m.containsKey(h)){var p=m.get(h);int cl=r-(int)p[0];long ce=t-p[1],q=(C-r)/cl;t+=q*ce;r+=q*cl;break;}m.put(h,new long[]{r,t});int c=L,j=h;long e=0;for(int i=0;i<N&&g[j]<=c;i++){c-=g[j];e+=g[j];j=(j+1)%N;}t+=e;r++;h=j;}while(r<C){int c=L,j=h;long e=0;for(int i=0;i<N&&g[j]<=c;i++){c-=g[j];e+=g[j];j=(j+1)%N;}t+=e;r++;h=j;}System.out.println(t);}}